from pathlib import Path
p=Path('index.html');s=p.read_text(encoding='utf-8')
if 'MOBILE_FLOATING_MENU_V1' in s: raise SystemExit('already applied')

needle='''        </div>\n    </div>\n</div>\n\n<div class="mobile-nav-container no-print" id="mobileNav">'''
repl='''        </div>\n    </div>\n    <button type="button" class="mobile-header-toggle" id="mobileHeaderToggle" onclick="toggleMobileHeader()" aria-expanded="true" title="헤더 접기"><span class="mobile-header-toggle-arrow" aria-hidden="true">⌃</span><span class="mobile-header-toggle-text">헤더 접기</span></button>\n</div>\n\n<div class="mobile-menu-backdrop no-print" id="mobileMenuBackdrop" onclick="closeMobileMenu()" aria-hidden="true"></div>\n<div class="mobile-nav-container no-print" id="mobileNav" role="dialog" aria-modal="true" aria-label="주요 메뉴" aria-hidden="true">\n    <div class="mobile-menu-heading"><strong>메뉴</strong><button type="button" class="mobile-menu-x" onclick="closeMobileMenu()" aria-label="메뉴 닫기">×</button></div>'''
if s.count(needle)!=1: raise SystemExit('header/nav marker mismatch')
s=s.replace(needle,repl,1)
needle='''        <button class="btn" id="m_btn_request" onclick="switchTab('request')"><span class="mobile-nav-icon" aria-hidden="true">✍️</span><span class="mobile-nav-label">수정 요청</span></button>\n    </div>\n</div>\n\n<div class="container" id="mainContainer"></div>'''
repl='''        <button class="btn" id="m_btn_request" onclick="switchTab('request')"><span class="mobile-nav-icon" aria-hidden="true">✍️</span><span class="mobile-nav-label">수정 요청</span></button>\n    </div>\n    <button type="button" class="mobile-menu-close" onclick="closeMobileMenu()">닫기</button>\n</div>\n<button type="button" class="mobile-menu-fab no-print" id="mobileMenuFab" onclick="toggleMobileMenu()" aria-expanded="false" aria-controls="mobileNav"><span class="mobile-menu-fab-icon" aria-hidden="true">☰</span><span>메뉴</span></button>\n\n<div class="container" id="mainContainer"></div>'''
if s.count(needle)!=1: raise SystemExit('nav close marker mismatch')
s=s.replace(needle,repl,1)

css='''\n/* MOBILE_FLOATING_MENU_V1 */\n.mobile-menu-fab,.mobile-menu-backdrop,.mobile-header-toggle{display:none}\n@media(max-width:850px){body.mobile-mode-active .mobile-menu-fab{position:fixed;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:1px;right:max(12px,env(safe-area-inset-right));bottom:max(12px,env(safe-area-inset-bottom));width:68px;height:68px;border:3px solid var(--border-heavy);border-radius:50%;background:var(--accent);color:#fff;font:inherit;font-size:13px;font-weight:900;cursor:pointer;box-shadow:0 7px 22px rgba(0,0,0,.28);z-index:2060;touch-action:manipulation}body.mobile-mode-active .mobile-menu-fab-icon{font-size:23px;line-height:1}body.mobile-mode-active .mobile-menu-backdrop{display:none;position:fixed;inset:0;background:rgba(0,0,0,.34);z-index:2020}body.mobile-mode-active.mobile-menu-open .mobile-menu-backdrop{display:block}body.mobile-mode-active .mobile-nav-container{display:none;position:fixed;left:auto;right:max(12px,env(safe-area-inset-right));bottom:calc(max(12px,env(safe-area-inset-bottom)) + 78px);width:min(360px,calc(100vw - 24px));max-width:calc(100vw - 24px);padding:10px;border:2px solid var(--border-heavy);border-radius:16px;background:var(--surface);box-shadow:0 12px 32px rgba(0,0,0,.32);overflow:visible;transform:none;z-index:2050}body.mobile-mode-active.mobile-menu-open .mobile-nav-container{display:block}body.mobile-mode-active .mobile-nav-container .controls{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:7px;width:100%;padding:0;overflow:visible}body.mobile-mode-active .mobile-nav-container .btn{display:flex;flex-direction:column;align-items:center;justify-content:center;gap:4px;width:100%;min-width:0;min-height:64px;padding:8px 6px;border:2px solid transparent;border-radius:10px;font-size:13px;line-height:1.15;overflow:visible;background:var(--bg)}body.mobile-mode-active .mobile-nav-container .btn.active{border-color:var(--border-heavy);background:var(--border-heavy);color:#fff}body.mobile-mode-active .mobile-nav-container .mobile-nav-icon{font-size:22px}body.mobile-mode-active .mobile-nav-container .mobile-nav-label{white-space:normal;text-align:center;font-weight:900}body.mobile-mode-active .mobile-menu-heading{display:flex;align-items:center;justify-content:space-between;min-height:38px;padding:0 2px 8px;font-size:17px}body.mobile-mode-active .mobile-menu-x{display:grid;place-items:center;width:38px;height:38px;border:2px solid var(--border-heavy);border-radius:50%;background:var(--surface);color:var(--text-main);font-size:26px;line-height:1;cursor:pointer}body.mobile-mode-active .mobile-menu-close{width:100%;min-height:48px;margin-top:8px;border:2px solid var(--border-heavy);border-radius:9px;background:var(--surface);color:var(--text-main);font:inherit;font-weight:900;cursor:pointer}body.mobile-mode-active .container{padding-bottom:var(--mobile-nav-clearance,94px)!important;scroll-padding-bottom:var(--mobile-nav-clearance,94px)}body.mobile-mode-active .header-wrapper{padding-bottom:0}body.mobile-mode-active .mobile-header-toggle{display:flex;align-items:center;justify-content:center;gap:5px;width:100%;min-height:27px;margin-top:4px;border:0;border-top:1px solid var(--border-heavy);background:var(--surface);color:var(--text-muted);font:inherit;font-size:11px;font-weight:900;cursor:pointer;touch-action:manipulation}body.mobile-mode-active .mobile-header-toggle-arrow{font-size:16px;line-height:1}body.mobile-mode-active.mobile-header-collapsed .header-wrapper{padding-top:max(2px,env(safe-area-inset-top));padding-left:0;padding-right:0}body.mobile-mode-active.mobile-header-collapsed .header-wrapper .header{display:none!important}body.mobile-mode-active.mobile-header-collapsed .mobile-header-toggle{margin-top:0;min-height:30px;border-top:0;border-bottom:2px solid var(--border-heavy)}}\n@media print{.mobile-menu-fab,.mobile-menu-backdrop,.mobile-header-toggle{display:none!important}}\n'''
i=s.rfind('</style>');
if i<0: raise SystemExit('style end missing')
s=s[:i]+css+s[i:]

js='''\n/* MOBILE_HEADER_COLLAPSE_V1 */\nconst MHKEY='academic-calendar-mobile-header-collapsed-v1';let mobileMenuReturnFocus=null;function mobileShell(){return document.body.classList.contains('mobile-mode-active')&&matchMedia('(max-width:850px)').matches}function setMobileMenu(open,restore=false){const on=!!open&&mobileShell(),nav=q('#mobileNav'),fab=q('#mobileMenuFab'),back=q('#mobileMenuBackdrop');if(on)mobileMenuReturnFocus=document.activeElement;document.body.classList.toggle('mobile-menu-open',on);if(nav){nav.setAttribute('aria-hidden',on?'false':'true');nav.inert=!on}if(fab)fab.setAttribute('aria-expanded',on?'true':'false');if(back)back.setAttribute('aria-hidden',on?'false':'true');syncMobileNavLayout();if(on)requestAnimationFrame(()=>{(q('#mobileNav .btn.active')||q('#mobileNav .btn'))?.focus({preventScroll:true})});else if(restore&&mobileMenuReturnFocus?.focus)mobileMenuReturnFocus.focus({preventScroll:true})}function toggleMobileMenu(){setMobileMenu(!document.body.classList.contains('mobile-menu-open'),true)}function closeMobileMenu(){setMobileMenu(false,true)}window.toggleMobileMenu=toggleMobileMenu;window.closeMobileMenu=closeMobileMenu;function setMobileHeaderCollapsed(v,persist=true){const on=!!v,b=q('#mobileHeaderToggle');document.body.classList.toggle('mobile-header-collapsed',on);if(b){b.setAttribute('aria-expanded',on?'false':'true');b.title=on?'헤더 펼치기':'헤더 접기';q('.mobile-header-toggle-arrow',b).textContent=on?'⌄':'⌃';q('.mobile-header-toggle-text',b).textContent=on?'헤더 펼치기':'헤더 접기'}if(persist)try{localStorage.setItem(MHKEY,on?'1':'0')}catch{}requestAnimationFrame(()=>{syncAppViewportHeight();resetOuterDocumentScroll(true)})}function toggleMobileHeader(){setMobileHeaderCollapsed(!document.body.classList.contains('mobile-header-collapsed'))}window.toggleMobileHeader=toggleMobileHeader;syncMobileNavLayout=function(){if(!mobileShell()){document.documentElement.style.removeProperty('--mobile-nav-clearance');setMobileMenu(false,false);return}document.documentElement.style.setProperty('--mobile-nav-clearance','94px')};const fmSwitch=switchTab;switchTab=function(id){setMobileMenu(false,false);fmSwitch(id)};const fmToggle=toggleMobileMode;toggleMobileMode=function(){setMobileMenu(false,false);fmToggle();if(!mobileShell())document.body.classList.remove('mobile-header-collapsed');else setMobileHeaderCollapsed((()=>{try{return localStorage.getItem(MHKEY)==='1'}catch{return false}})(),false);syncMobileNavLayout()};document.addEventListener('keydown',e=>{if(e.key==='Escape'&&document.body.classList.contains('mobile-menu-open'))closeMobileMenu()});window.addEventListener('resize',()=>{if(!mobileShell())setMobileMenu(false,false);syncMobileNavLayout()},{passive:true});setMobileMenu(false,false);setMobileHeaderCollapsed((()=>{try{return localStorage.getItem(MHKEY)==='1'}catch{return false}})(),false);syncMobileNavLayout();\n'''
mark='restore();header();createPanel();applyScale();updateModeControls();enhance();\n})();'
if s.count(mark)!=1: raise SystemExit('script marker mismatch')
s=s.replace(mark,'restore();header();createPanel();applyScale();updateModeControls();enhance();'+js+'\n})();',1)
for x in ['MOBILE_FLOATING_MENU_V1','MOBILE_HEADER_COLLAPSE_V1','id="mobileMenuFab"','id="mobileHeaderToggle"']:
 if x not in s: raise SystemExit('missing '+x)
p.write_text(s,encoding='utf-8')
